if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026 || !$env.GDA_WEBHOOK_KEY) throw new Error('Required auth env vars not set (GDA_API_KEY_2026, GDA_DEPLOY_KEY_2026, GDA_WEBHOOK_SECRET_2026, GDA_WEBHOOK_KEY)');
const N8N='https://n8n.csr-llc.tech/webhook';
const AUTH={auth_key:$env.GDA_API_KEY_2026};
const results=[];

async function test(name,endpoint,payload,validate){
  const start=Date.now();
  try{
    const d=await this.helpers.httpRequest({
      method:'POST',
      url:N8N+'/'+endpoint,
      headers:{'Content-Type':'application/json','x-gda-key':$env.GDA_WEBHOOK_KEY||''},
      body:{...AUTH,...payload},
      json:true,
      timeout:15000
    });
    const ms=Date.now()-start;
    const issue=validate?validate(d):null;
    if(issue){results.push({name,endpoint,status:'WARN',ms,issue});}
    else{results.push({name,endpoint,status:'PASS',ms,records:Array.isArray(d.data)?d.data.length:d.data?1:0});}
  }catch(e){
    const ms=Date.now()-start;
    const code=e.response?.status||e.statusCode||null;
    results.push({name,endpoint,status:'FAIL',ms,code,error:code?'HTTP '+code+' — '+endpoint:e.message||'Request failed'});
  }
}

await test('Opp Tracker','gda-opp-tracker',{action:'list'},d=>!d.data&&!Array.isArray(d)?'No data returned':null);
